-- {"operators": "OUTER_JOIN,AGGREGATE", "complexity": "high", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": true, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,OORDER,ORDER_LINE,STOCK"}
SELECT w.W_ID, d.D_ID, c.C_ID, c.C_LAST, c.C_CREDIT, COUNT(o.O_ID) AS order_count, SUM(ol.OL_AMOUNT) AS lifetime_spend, COALESCE(SUM(CASE WHEN s.S_QUANTITY < 5 THEN 1 ELSE 0 END), 0) AS critical_stock_lines FROM WAREHOUSE w LEFT JOIN DISTRICT d ON w.W_ID = d.D_W_ID LEFT JOIN CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID LEFT JOIN OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID LEFT JOIN ORDER_LINE ol ON o.O_W_ID = ol.OL_W_ID AND o.O_D_ID = ol.OL_D_ID AND o.O_ID = ol.OL_O_ID LEFT JOIN STOCK s ON ol.OL_W_ID = s.S_W_ID AND ol.OL_I_ID = s.S_I_ID GROUP BY w.W_ID, d.D_ID, c.C_ID, c.C_LAST, c.C_CREDIT;
